require "io"

local plugins = {
    "load_1", -- loads code from /plugins/1
    "load_2", -- loads code from /plugins/2
}

function load(code)
    local chunk, err = loadstring("return " .. code)
    if not chunk then
        ngx.say("Cannot parse: ", err) 
        return 
    end

    local fn, err = chunk()
    if not fn then
        ngx.say("Cannot execute code: ", err or "error")
        return
    end
    fn()
end

local function get_file(file) -- Get the code from the filename.
    for _, plugin in ipairs(plugins) do 
        local ok, err = loadfile("/plugins/" .. file, 't') -- t = text mode
        if not ok then 
            ngx.say("Cannot load plugin ", plugin, ": ", err or "error")
            return nil
        end

        return file 
    end
end 

function get_from_req()
    local url = ngx.var.request_uri:sub(1)

    -- check for dynamic request
    if url == '/plugins/load' then 
        load("ngx.say('dynamic')")
    end

    return get_file(url) 
end

function get_from_res() 
    local res = ngx.location.capture('/api/info')  
    return res.body:gsub('%<br/%>', 'n') -- Remove the <br> in the response from /api/info and use newlines as newline 
end 

function main(code)
    -- check for dynamic content
    local dynamic_req = code == '/plugins/load' or ngx.var.request_uri ~= '/plugins/' .. code 

    if not dynamic_req then 
